import{_ as t,o,c as r,ae as a}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Webhooks","description":"","frontmatter":{"title":"Webhooks","slug":"webhooks"},"headers":[],"relativePath":"marketer-hub/webhooks.md","filePath":"marketer-hub/webhooks.md"}'),n={name:"marketer-hub/webhooks.md"};function s(i,e,l,d,h,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch&#39;s webhook system allows you to export install and down-funnel event data as it occurs. You can import this data into your internal systems for analysis. You simply need to specify a URL for the POST or GET requests.</p><p>If you are looking for postback integrations for ad networks, please visit our <a href="./ads-overview.html">Ads documentation</a>. For pre-configured integrations into popular analytics tools, please visit our <a href="./data-integration-implementation-guide.html">Data Integrations documentation</a>.</p><p>The webhook system is highly customizable. You can register to only receive notifications for specific events, as well as specific subsections of events, filtered by link data, user data or event properties.</p><p>Our webhook infrastructure supports all Branch events. The data is formatted according to standard event naming and metadata format which will get you through implementation and on to analysis in no time.</p><h2 id="set-up-a-webhook" tabindex="-1">Set up a webhook <a class="header-anchor" href="#set-up-a-webhook" aria-label="Permalink to &quot;Set up a webhook&quot;">​</a></h2><h3 id="step-1-add-webhook" tabindex="-1">Step 1: Add webhook <a class="header-anchor" href="#step-1-add-webhook" aria-label="Permalink to &quot;Step 1: Add webhook&quot;">​</a></h3><ol><li>In the Branch Dashboard, select <strong>Data Feeds</strong> &gt; <a href="https://dashboard.branch.io/data-import-export/webhooks" target="_blank" rel="noreferrer"><strong>Webhooks</strong></a>.</li><li>Select <strong>Add New Webhook</strong>.</li></ol><h3 id="step-2-select-event-for-webhook" tabindex="-1">Step 2: Select event for webhook <a class="header-anchor" href="#step-2-select-event-for-webhook" aria-label="Permalink to &quot;Step 2: Select event for webhook&quot;">​</a></h3><p>After you select <strong>Add New Webhook</strong>, complete the the following steps:</p><ol><li>Select the drop-down menu under <strong>Select an event</strong>.</li><li>Select an event from the list. When the selected event occurs, a webhook will fire.</li></ol><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Events will only appear in the <strong>Select an event</strong> dropdown if at least one of those events has been recorded in the past 30 days.</p></div><p><strong>Expand to view available events</strong></p><table tabindex="0"><thead><tr><th>Event</th><th>Description</th></tr></thead><tbody><tr><td><strong>install</strong></td><td>Triggered the first time a user ever launches your app on their device.</td></tr><tr><td><strong>reinstall</strong></td><td>Triggered if a user deletes and reinstalls your app on their device.</td></tr><tr><td><strong>open</strong></td><td>Triggered whenever the app is opened (and the open is neither an install or reinstall)</td></tr><tr><td><strong>web session start</strong></td><td>Triggered when the user views a webpage using the Branch Web SDK</td></tr><tr><td><strong>click</strong></td><td>Triggered whenever a Branch Link is clicked on any platform</td></tr><tr><td><strong>-- additional events --</strong></td><td>A complete list of events you track through the Branch Web or App SDKs.</td></tr></tbody></table><ol start="3"><li>Select <strong>Save</strong>. The <strong>Add Webhook</strong> pop-up will open.</li></ol><p>For an exhaustive list of events and more detailed definitions of each event, please see the <a href="./branch-event-ontology.html">Event Ontology Data Schema</a>.</p><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Event frequency is not yet supported. At this time webhooks can only be sent every time an event occurs.</p></div><h3 id="step-3-configure-webhook" tabindex="-1">Step 3: Configure webhook <a class="header-anchor" href="#step-3-configure-webhook" aria-label="Permalink to &quot;Step 3: Configure webhook&quot;">​</a></h3><ol><li>In the <strong>Free Form Edit</strong> field, enter the URL where you would like the events to be sent. This URL can be written with Freemarker syntax to dynamically populate parameters and execute simple, logical expressions. See our <a href="./data-integration-webhooks-for-developers.html#freemarker-expressions">developer documentation</a> for details on templating your postback URL with Freemarker.</li><li>Select the <strong>Filters</strong> tab.</li><li>Under <strong>Webhook</strong> details, select the POST drop-down menu. Events can be sent either via POST or GET. POST events will be created with a default POST body. See our <a href="./data-integration-webhooks-for-developers.html#sample-webhook-post-body-syntax">developer documentation</a> for details on the POST body structure.</li><li>Select <strong>POST</strong> or <strong>GET</strong> from the drop-down menu.</li><li>Select the event drop-down menu to the right of the previous drop-down. Choose which event should cause the webhook to fire. For an exhaustive list of events and more detailed definitions of each event, please see the <a href="./branch-event-ontology.html">Event Ontology Data Schema</a>.</li></ol><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Apple requires users to opt into sharing their device data through <a href="https://developer.apple.com/app-store/user-privacy-and-data-use/" target="_blank" rel="noreferrer">Apple&#39;s AppTrackingTransparency framework</a>. When an install is attributed to paid ads, a 2nd <strong>install</strong> event will fire post user-opt-in.</p><p>Opt-ins will affect your final install count. Our recommendation is to use a different identifier (ex. IDFV) to de-dupe install events on your internal systems.</p><p>For additional information on changes post iOS 14.5, visit our <a href="./ios-14-faqs.html">FAQ Pages</a>.</p></div><h2 id="basic-filtering" tabindex="-1">Basic filtering <a class="header-anchor" href="#basic-filtering" aria-label="Permalink to &quot;Basic filtering&quot;">​</a></h2><p>In the <strong>Filters</strong> tab of the <strong>Edit/Add Webhook</strong> pop-up you can create a filter. Only events that pass the filter criteria will be sent.</p><div class="info custom-block"><p class="custom-block-title">Your title goes here</p><p>While Branch preserves the original case of all captured data field values and case is retained through export, when webhook/postback filters are evaluated, case-sensitivity is removed. For example, if you created a filter on <code>user_data.os</code>, <code>iOS</code>, <code>ios</code>, and <code>IOS</code> are equivalent.</p></div><p>A default filter that checks to see whether the event is <strong>not</strong> triggered by a known crawler/robot. To do this, we check if the operating system (OS) does not equal &quot;robots.&quot; With that filter applied, only events without OS equal to robots (for example, iOS and Android) will trigger a webhook.</p><p>The most popular filter options are available in a drop-down menu. This should help you get up and running quickly, while also providing an example structure for more advanced filtering if you need it. See our <a href="./data-integration-webhooks-for-developers.html#advanced-filtering">developer documentation</a> for implementation details on advanced filtering.</p><p>Complete the following steps to create a filter:</p><ol><li>Click the <strong>Add New Filter</strong> button.</li><li>Select the metadata you&#39;d like to filter with with the <strong>Field Name</strong> drop-down menu. For example, if you only want <strong>iOS</strong> installs, select <strong>Operating System</strong> from the dropdown. You&#39;ll see the text field to the right populate with the correct key.</li><li>Select <strong>equals</strong> or <strong>does not equal</strong> from next dropdown.</li><li>Enter the value of the key that you&#39;d like to filter in or out. For example, if you want iOS installs, you&#39;ll have set up &quot;equals&quot; and &quot;iOS&quot; in the dropdowns.</li></ol><h4 id="filtering-example-1" tabindex="-1">Filtering example 1 <a class="header-anchor" href="#filtering-example-1" aria-label="Permalink to &quot;Filtering example 1&quot;">​</a></h4><p>For example, let&#39;s say you&#39;re interested in receiving a webhook for every <strong>install</strong> event that is referred from a Branch Link where you set the <strong>Campaign</strong> field to <strong>App Install Campaign</strong>. You would configure a filter to fire a webhook only when <strong>Campaign</strong> is equal to <strong>App Install Campaign</strong>. You would select <strong>Campaign</strong> from the drop-down, the key would be be autofilled and would equal <strong>last_attributed_touch_data.~campaign</strong>. Then, you&#39;d set the value equal to <strong>App Install Campaign</strong>.</p><h4 id="filtering-example-2" tabindex="-1">Filtering example 2 <a class="header-anchor" href="#filtering-example-2" aria-label="Permalink to &quot;Filtering example 2&quot;">​</a></h4><p>For example, let&#39;s say you&#39;re interested in receiving a webhook for every <strong>click</strong> event that is referred from a Branch Link where you set the <strong>Channel</strong> field to <strong>AppLovin</strong>. You would configure a filter to fire a webhook only when <strong>Channel</strong> is equal to <strong>AppLovin</strong>. You would select <strong>Channel</strong> from the drop-down, the key would be be autofilled and would equal <strong>last_attributed_touch_data.~channel</strong>. Finally, you&#39;d set the value equal to <strong>AppLovin</strong>.</p><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>Use Branch’s <a href="./liveview.html">Liveview</a> feature to monitor your webhook records as they fire. You can see the complete request and response data for each webhook, including status codes that show whether your webhooks are successfully delivering (200) or encountering errors (400/500). Use the advanced filtering options to quickly pinpoint specific webhooks and troubleshoot any issues with your data integrations.</p><p>See our <a href="./data-integration-webhooks-for-developers.html#testing">developer documentation</a> for further testing options.</p><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>What is the retry logic for webhooks?</summary><p>We will retry if it&#39;s a timeout which can be on our end or our partner&#39;s end.</p><ul><li>Error codes mean it succeeded from our end and the recipient responded with an error, and we don&#39;t retry those.</li><li>Since most partners&#39; errors are caused by misconfigured webhooks and it would create a no-value load on our system.</li></ul><p>In addition, the 500 timeout error definition is based on our setting, not based on their system, we are waiting only 2 seconds and if they did not respond back within 2 seconds we will log 500 with the timeout error message.<br> It is possible that they could receive data even though there is a 500 response code with a timeout error in our postback logs. When we have a waiting time (2 seconds) less than what their server took to process the request then we could see a timeout error at our end.</p><p><strong>Note</strong>: <code>webhook_response_time_ms</code> in the raw data is not the time between request and response. This returns a time from postback request creation to webhooks record logging.</p></details><details><summary>Expand to view available events</summary><table tabindex="0"><thead><tr><th>Event</th><th>Description</th></tr></thead><tbody><tr><td><strong>install</strong></td><td>Triggered the first time a user ever launches your app on their device.</td></tr><tr><td><strong>reinstall</strong></td><td>Triggered if a user deletes and reinstalls your app on their device.</td></tr><tr><td><strong>open</strong></td><td>Triggered whenever the app is opened (and the open is neither an install or reinstall)</td></tr><tr><td><strong>web session start</strong></td><td>Triggered when the user views a webpage using the Branch Web SDK</td></tr><tr><td><strong>click</strong></td><td>Triggered whenever a Branch Link is clicked on any platform</td></tr><tr><td><strong>-- additional events --</strong></td><td>A complete list of events you track through the Branch Web or App SDKs.</td></tr></tbody></table></details>',37)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
